{
  "type": "CAROUSEL",
  "lessonText": "Explore essential Python libraries for enhancing game development.",
  "data": {
    "slides": [
      {
        "title": "Pygame",
        "content": "A popular library for creating 2D games in Python. \n- Simple API. \n- Supports graphics, sound, and input. \n- Great for beginners.",
        "imagePrompt": "Pygame logo",
        "imageUrl": "https://www.pygame.org/docs/images/pygame_logo.png"
      },
      {
        "title": "Panda3D",
        "content": "A powerful engine for 3D game development. \n- Supports Python scripting. \n- Real-time rendering. \n- Ideal for complex games.",
        "imagePrompt": "Panda3D logo",
        "imageUrl": "https://www.panda3d.org/images/panda3d_logo.png"
      },
      {
        "title": "PyOpenGL",
        "content": "A Python binding to OpenGL for 3D graphics. \n- Low-level access to OpenGL. \n- High performance. \n- Suitable for advanced developers.",
        "imagePrompt": "PyOpenGL logo",
        "imageUrl": "https://pyopengl.sourceforge.io/images/pyopengl_logo.png"
      },
      {
        "title": "Arcade",
        "content": "A modern library for 2D games with Python. \n- Easy to learn. \n- Supports physics and animations. \n- Good for educational purposes.",
        "imagePrompt": "Arcade library logo",
        "imageUrl": "https://arcade.academy/en/latest/_static/arcade_logo.png"
      }
    ]
  }
}
